            var rsvpLockedRaw = firstDefined(
              payload && payload.rsvps_locked,
              payload && payload.rsvp_locked,
              payload && payload.rsvpLocked,
              payload && payload.rsvpsLocked,
              invitation && invitation.rsvps_locked,
              invitation && invitation.rsvp_locked,
              invitation && invitation.rsvpLocked,
              invitation && invitation.rsvpsLocked
            );

            var wishesVisibility = firstNonEmpty(
              payload && payload.wishes_visibility,
              payload && payload.wishesVisibility,
              invitation && invitation.wishes_visibility,
              invitation && invitation.wishesVisibility
            ).toLowerCase();

            var rsvpVisibility = firstNonEmpty(
              payload && payload.rsvp_visibility,
              payload && payload.rsvps_visibility,
              payload && payload.rsvpVisibility,
              payload && payload.rsvpsVisibility,
              invitation && invitation.rsvp_visibility,
              invitation && invitation.rsvps_visibility,
              invitation && invitation.rsvpVisibility,
              invitation && invitation.rsvpsVisibility
            ).toLowerCase();

            var wishesLocked = wishesLockedRaw !== undefined
              ? normalizeLockFlag(wishesLockedRaw)
              : (wishesVisibility === 'password' ? true : normalizeLockFlag(previous.wishesLocked));

            var rsvpLocked = rsvpLockedRaw !== undefined
              ? normalizeLockFlag(rsvpLockedRaw)
              : (rsvpVisibility === 'password' ? true : normalizeLockFlag(previous.rsvpLocked));

