          if (section === 'rsvp') {
            return String(
              firstDefined(
                lockStatus.password_rsvp,
                lockStatus.passwordRsvp,
                lockStatus.rsvpPassword,
                ''
              ) || ''
            ).trim();
          }

          return '';
