              var rsvpUnlocked = HAS_RSVP_PASSWORD
                ? (submittedRsvpPassword
                  ? resolveSectionUnlocked('rsvp', payload, { allowCollectionUnlock: true })
                  : !currentLockState.rsvpLocked)
                : true;

              var submittedAnyPassword = !!wishesPassword || !!rsvpPassword;
              var submittedAnySuccess = (!!wishesPassword && wishesUnlocked) || (!!rsvpPassword && rsvpUnlocked);

              if (submittedAnyPassword && !submittedAnySuccess) {
                throw new Error('INCORRECT_PASSWORD');
              }

              console.log('✅ Password verified:', {
                wishesUnlocked: wishesUnlocked,
                rsvpUnlocked: rsvpUnlocked,
                payload: payload
              });

              if (submittedWishesPassword && wishesUnlocked) {
                sessionStorage.setItem('invitation_' + slug + '_wishes', enteredWishesPassword);
                console.log('💾 Saved wishes password to session');
              }

              if (submittedRsvpPassword && rsvpUnlocked) {
                sessionStorage.setItem('invitation_' + slug + '_rsvp', enteredRsvpPassword);
                console.log('💾 Saved RSVP password to session');
              }

              updateRuntimeLockFlags(wishesUnlocked, rsvpUnlocked, slug);

              var fullyUnlocked = (!HAS_WISHES_PASSWORD || wishesUnlocked) && (!HAS_RSVP_PASSWORD || rsvpUnlocked);
              if (fullyUnlocked) {
                dismissLockButton();
                closePasswordModal();
              } else {
                var nextLockState = syncModalFieldsWithLockState();

                if (errorEl) {
                  errorEl.style.display = 'none';
                  errorEl.textContent = '';
                }

                var wishesInput = document.getElementById('hiweb-wishes-password');
                var rsvpInput = document.getElementById('hiweb-rsvp-password');

                if (wishesUnlocked && wishesInput) wishesInput.value = '';
                if (rsvpUnlocked && rsvpInput) rsvpInput.value = '';

                var nextFocusInput = nextLockState.wishesLocked
                  ? wishesInput
                  : (nextLockState.rsvpLocked ? rsvpInput : null);

                if (nextFocusInput) {
                  setTimeout(function() {
                    nextFocusInput.focus();
                  }, 80);
                }
              }

