    posX = x;
    posY = y;
    targetX = x;
    targetY = y;
    lockContainer.style.left = x + 'px';
    lockContainer.style.top = y + 'px';
    lockContainer.style.right = 'auto';
    lockContainer.style.bottom = 'auto';
